mapper.select:
SELECT COUNT(1)
FROM cage_shelf_index
WHERE shelve_id = #{shelveId}

SELECT CAST(floor_id AS CHAR) AS floorId,
       floor_name AS floorName
FROM cage_shelf_index
WHERE deleted = 0
  AND campus_id = #{campusId}
  AND CAST(area_id AS CHAR) = #{areaId}
  AND area_name = #{areaName}
GROUP BY floor_id, floor_name
ORDER BY floor_id ASC

SELECT CAST(room_id AS CHAR) AS roomId,
       room_name AS roomName
FROM cage_shelf_index
WHERE deleted = 0
  AND campus_id = #{campusId}
  AND CAST(area_id AS CHAR) = #{areaId}
  AND area_name = #{areaName}
  AND CAST(floor_id AS CHAR) = #{floorId}
  AND floor_name = #{floorName}
GROUP BY room_id, room_name
ORDER BY room_id ASC

SELECT CAST(shelve_id AS CHAR) AS shelveId,
       shelve_name AS shelveName
FROM cage_shelf_index
WHERE deleted = 0
  AND campus_id = #{campusId}
  AND CAST(area_id AS CHAR) = #{areaId}
  AND area_name = #{areaName}
  AND CAST(floor_id AS CHAR) = #{floorId}
  AND floor_name = #{floorName}
  AND CAST(room_id AS CHAR) = #{roomId}
  AND room_name = #{roomName}
GROUP BY shelve_id, shelve_name
ORDER BY shelve_id ASC

SELECT COUNT(1)
FROM cage_shelf_index
WHERE deleted = 0
  AND campus_id = #{campusId}
  AND CAST(area_id AS CHAR) = #{areaId}
  AND CAST(floor_id AS CHAR) = #{floorId}
  AND CAST(room_id AS CHAR) = #{roomId}
